export const getGetDroppedUrl = (params?: GetDroppedParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/donghua/drop?${stringifiedParams}` : `/api/donghua/drop`
}

/**
 * Returns donghua series that have been dropped
 * @summary Get dropped donghua list
 */
export const getDropped = async (params?: GetDroppedParams, options?: RequestInit): Promise<DonghuaListResponse> => {

  return customFetch<DonghuaListResponse>(getGetDroppedUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetDroppedQueryKey = (params?: GetDroppedParams,) => {
    return [
    `/api/donghua/drop`, ...(params ? [params] : [])
    ] as const;
    }


